/**
 * Soluctions S.A - Combined & Optimized JavaScript
 * Arquivo consolidado para melhor performance
 */

document.addEventListener("DOMContentLoaded", () => {
  document.body.classList.add("fouc-ready");
  initPreloader();
  initScrollObserver();
  initUIInteractions();
  initVisualEffects();
  initCounters();
  initChatbot();
  initMobileOptimizations();
  initServicesCarousel();

  if (typeof AOS !== "undefined") {
    AOS.init({
      duration: 800,
      easing: "ease-in-out",
      once: true,
      mirror: false,
      offset: 50,
    });
  }
});

// Preloader otimizado
function initPreloader() {
  const loader = document.querySelector(".loader");
  const loaderFill = document.querySelector(".loader-progress-fill");

  if (!loader || !loaderFill) return;

  setTimeout(() => {
    loaderFill.style.width = "100%";
  }, 100);

  setTimeout(() => {
    loader.style.opacity = "0";
    loader.style.transform = "scale(0.8)";
    setTimeout(() => {
      loader.style.display = "none";
    }, 300);
  }, 2500);
}

// Scroll observer otimizado
function initScrollObserver() {
  const scrollIndicator = document.querySelector(".scroll-indicator");
  const header = document.querySelector("header");

  let ticking = false;

  function updateScrollProgress() {
    const scrollTop = window.pageYOffset;
    const docHeight =
      document.documentElement.scrollHeight - window.innerHeight;
    const scrollPercent = (scrollTop / docHeight) * 100;

    if (scrollIndicator) {
      scrollIndicator.style.width = scrollPercent + "%";
    }

    if (header) {
      header.classList.toggle("scrolled", scrollTop > 50);
    }

    ticking = false;
  }

  window.addEventListener(
    "scroll",
    () => {
      if (!ticking) {
        requestAnimationFrame(updateScrollProgress);
        ticking = true;
      }
    },
    { passive: true }
  );
}

// UI Interactions consolidadas
function initUIInteractions() {
  // Mobile menu
  const mobileMenuBtn = document.querySelector(".mobile-menu-btn");
  const mobileNav = document.querySelector(".mobile-nav");
  const mobileNavOverlay = document.querySelector(".mobile-nav-overlay");
  const mobileNavClose = document.querySelector(".mobile-nav-close");

  function toggleMobileMenu() {
    mobileNav?.classList.toggle("translate-x-full");
    mobileNavOverlay?.classList.toggle("hidden");
  }

  mobileMenuBtn?.addEventListener("click", toggleMobileMenu);
  mobileNavClose?.addEventListener("click", toggleMobileMenu);
  mobileNavOverlay?.addEventListener("click", toggleMobileMenu);

  // FAQ toggles
  document.querySelectorAll(".cyber-faq-question").forEach((question) => {
    question.addEventListener("click", () => {
      const item = question.parentElement;
      const answer = item.querySelector(".cyber-faq-answer");
      const icon = question.querySelector("i");

      if (answer.style.maxHeight && answer.style.maxHeight !== "0px") {
        answer.style.maxHeight = "0px";
        icon.style.transform = "rotate(0deg)";
      } else {
        answer.style.maxHeight = answer.scrollHeight + "px";
        icon.style.transform = "rotate(180deg)";
      }
    });
  });

  // Smooth scrolling
  document.querySelectorAll('a[href^="#"]').forEach((anchor) => {
    anchor.addEventListener("click", function (e) {
      e.preventDefault();
      const target = document.querySelector(this.getAttribute("href"));
      if (target) {
        target.scrollIntoView({
          behavior: "smooth",
          block: "start",
        });
      }
    });
  });
}

// Efeitos visuais otimizados
function initVisualEffects() {
  // Cursor personalizado (apenas desktop)
  if (window.innerWidth > 768) {
    const cursor = document.querySelector(".cursor");
    const cursorDot = document.querySelector(".cursor-dot");

    if (cursor && cursorDot) {
      let mouseX = 0,
        mouseY = 0;
      let cursorX = 0,
        cursorY = 0;

      document.addEventListener("mousemove", (e) => {
        mouseX = e.clientX;
        mouseY = e.clientY;
      });

      function animateCursor() {
        cursorX += (mouseX - cursorX) * 0.1;
        cursorY += (mouseY - cursorY) * 0.1;

        cursor.style.transform = `translate(${cursorX}px, ${cursorY}px)`;
        cursorDot.style.transform = `translate(${mouseX}px, ${mouseY}px)`;

        requestAnimationFrame(animateCursor);
      }

      animateCursor();
    }
  }

  // Particles.js otimizado
  if (typeof particlesJS !== "undefined") {
    particlesJS("particles-js", {
      particles: {
        number: { value: window.innerWidth < 768 ? 30 : 60 },
        color: { value: "#00f3ff" },
        shape: { type: "circle" },
        opacity: { value: 0.3, random: true },
        size: { value: 2, random: true },
        line_linked: {
          enable: true,
          distance: 150,
          color: "#00f3ff",
          opacity: 0.2,
          width: 1,
        },
        move: {
          enable: true,
          speed: 2,
          direction: "none",
          random: false,
          straight: false,
          out_mode: "out",
          bounce: false,
        },
      },
      interactivity: {
        detect_on: "canvas",
        events: {
          onhover: { enable: window.innerWidth > 768, mode: "repulse" },
          onclick: { enable: true, mode: "push" },
          resize: true,
        },
      },
      retina_detect: true,
    });
  }
}

// Contadores animados
function initCounters() {
  const counters = document.querySelectorAll(".counter");
  const observerOptions = {
    threshold: 0.5,
    rootMargin: "0px 0px -50px 0px",
  };

  const observer = new IntersectionObserver((entries) => {
    entries.forEach((entry) => {
      if (entry.isIntersecting) {
        const counter = entry.target;
        const target = parseInt(counter.getAttribute("data-target"));
        let current = 0;
        const increment = target / 50;

        const updateCounter = () => {
          if (current < target) {
            current += increment;
            counter.textContent = Math.ceil(current);
            requestAnimationFrame(updateCounter);
          } else {
            counter.textContent = target;
          }
        };

        updateCounter();
        observer.unobserve(counter);
      }
    });
  }, observerOptions);

  counters.forEach((counter) => observer.observe(counter));
}

// Chatbot otimizado
function initChatbot() {
  const chatbotButton = document.getElementById("chatbot-button");
  const chatbotBox = document.getElementById("chatbot-box");
  const chatbotClose = document.getElementById("chatbot-close");
  const chatbotMinimize = document.getElementById("chatbot-minimize");
  const chatbotSend = document.getElementById("chatbot-send");
  const chatbotInput = document.getElementById("chatbot-input");
  const chatbotMessages = document.getElementById("chatbot-messages");

  let isMinimized = false;

  // Respostas automáticas otimizadas
  const responses = {
    ola: "Olá! Como posso ajudá-lo hoje?",
    servicos:
      "Oferecemos gestão de anúncios, landing pages, social media com IA, chatbots e consultoria digital.",
    preco:
      "Nossos valores são personalizados. Entre em contato para uma consultoria gratuita!",
    contato:
      "Você pode nos contatar através do formulário ou pelos nossos escritórios em Zurich, Malta e Manchester.",
    default:
      "Interessante! Um de nossos especialistas entrará em contato em breve. Tem mais alguma dúvida?",
  };

  function addMessage(message, isUser = false) {
    const messageDiv = document.createElement("div");
    messageDiv.className = `cyber-chatbot-message ${isUser ? "user" : "bot"}`;
    messageDiv.innerHTML = `<p>${message}</p>`;
    chatbotMessages.appendChild(messageDiv);
    chatbotMessages.scrollTop = chatbotMessages.scrollHeight;
  }

  function getResponse(message) {
    const lowerMessage = message.toLowerCase();
    for (const [key, response] of Object.entries(responses)) {
      if (lowerMessage.includes(key)) return response;
    }
    return responses.default;
  }

  function sendMessage() {
    const message = chatbotInput.value.trim();
    if (!message) return;

    addMessage(message, true);
    chatbotInput.value = "";

    setTimeout(() => {
      addMessage(getResponse(message));
    }, 1000);
  }

  chatbotButton?.addEventListener("click", () => {
    chatbotBox?.classList.toggle("hidden");
    if (
      !chatbotBox?.classList.contains("hidden") &&
      chatbotMessages.children.length === 0
    ) {
      addMessage("Olá! Sou o assistente da Soluctions. Como posso ajudá-lo?");
    }
  });

  chatbotClose?.addEventListener("click", () => {
    chatbotBox?.classList.add("hidden");
  });

  chatbotSend?.addEventListener("click", sendMessage);
  chatbotInput?.addEventListener("keypress", (e) => {
    if (e.key === "Enter") sendMessage();
  });
}

// Otimizações mobile consolidadas
function initMobileOptimizations() {
  if (window.innerWidth <= 768) {
    // Reduzir animações em mobile
    document.querySelectorAll("[data-aos]").forEach((el) => {
      el.setAttribute("data-aos-duration", "400");
    });

    // Otimizar touch events
    document.addEventListener("touchstart", () => {}, { passive: true });
    document.addEventListener("touchmove", () => {}, { passive: true });
  }
}

// Carrossel de serviços mobile otimizado
function initServicesCarousel() {
  if (window.innerWidth > 768) return;

  const servicesSection = document.querySelector("#services");
  if (!servicesSection) return;

  const grid = servicesSection.querySelector(".grid");
  if (!grid) return;

  // Criar carrossel apenas se não existir
  let carouselContainer = servicesSection.querySelector(
    ".services-mobile-carousel"
  );
  if (carouselContainer) return;

  carouselContainer = document.createElement("div");
  carouselContainer.className = "services-mobile-carousel block md:hidden mb-8";
  carouselContainer.innerHTML = `
    <div class="services-carousel-wrapper overflow-hidden">
      <div class="services-carousel-track flex transition-transform duration-300 ease-out"></div>
    </div>
    <div class="flex justify-center mt-4 space-x-2">
      <button class="carousel-nav prev w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center disabled:opacity-50">
        <i class="fas fa-chevron-left text-sm"></i>
      </button>
      <button class="carousel-nav next w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center disabled:opacity-50">
        <i class="fas fa-chevron-right text-sm"></i>
      </button>
    </div>
  `;

  grid.parentNode.insertBefore(carouselContainer, grid);

  // Mover cards para o carrossel
  const serviceCards = grid.querySelectorAll(".cyber-service-card");
  const carouselTrack = carouselContainer.querySelector(
    ".services-carousel-track"
  );

  serviceCards.forEach((card) => {
    const wrapper = document.createElement("div");
    wrapper.className = "carousel-slide flex-shrink-0 w-full px-2";
    wrapper.appendChild(card.cloneNode(true));
    carouselTrack.appendChild(wrapper);
  });

  // Controles do carrossel
  let currentSlide = 0;
  const slides = carouselTrack.querySelectorAll(".carousel-slide");
  const prevBtn = carouselContainer.querySelector(".prev");
  const nextBtn = carouselContainer.querySelector(".next");

  function updateCarousel() {
    const translateX = -currentSlide * 100;
    carouselTrack.style.transform = `translateX(${translateX}%)`;

    prevBtn.disabled = currentSlide === 0;
    nextBtn.disabled = currentSlide >= slides.length - 1;
  }

  prevBtn?.addEventListener("click", () => {
    if (currentSlide > 0) {
      currentSlide--;
      updateCarousel();
    }
  });

  nextBtn?.addEventListener("click", () => {
    if (currentSlide < slides.length - 1) {
      currentSlide++;
      updateCarousel();
    }
  });

  updateCarousel();
  grid.style.display = "none";
}

// Handle resize events
window.addEventListener(
  "resize",
  () => {
    if (window.innerWidth > 768) {
      const carousel = document.querySelector(".services-mobile-carousel");
      const grid = document.querySelector("#services .grid");
      if (carousel) carousel.style.display = "none";
      if (grid) grid.style.display = "grid";
    } else {
      initServicesCarousel();
    }
  },
  { passive: true }
);
